const fs = require('fs');
const path = require('path');

const raw = $input.first().json;
const filePath = (raw.path || '').replace(/\\/g, '/');

// Only process .json files
if (!filePath.endsWith('.json')) return [];

let task;
try {
  task = JSON.parse(fs.readFileSync(filePath, 'utf8'));
} catch(e) {
  return [];
}

// Skip non-PENDING tasks (e.g. already processed on restart)
if ((task.status || '').toUpperCase() !== 'PENDING') return [];

const task_type = (task.task_type || 'CLASSIFY').toUpperCase();

let route, model;
if (task_type === 'RESEARCH') {
  route = 'RESEARCH';
  model = null;
} else if (task_type === 'CODE') {
  route = 'OLLAMA';
  model = 'qwen2.5-coder:7b';
} else if (task_type === 'VISION') {
  route = 'OLLAMA';
  model = 'minicpm-v:8b';
} else {
  // CLASSIFY, SUMMARIZE, COMPRESS, BLUEPRINT, and anything else
  route = 'OLLAMA';
  model = 'qwen3:14b';
}

const vault = 'C:/SFV_BLUEPRINT';

return [{
  json: {
    task_id:      task.task_id || path.basename(filePath, '.json'),
    topic:        task.topic || 'unknown',
    task_type,
    prompt:       task.prompt || '',
    priority:     task.priority || 'NORMAL',
    output_target: (task.output_target || '').replace(/\\/g, '/'),
    file_path:    filePath,
    route,
    model,
    vault
  }
}];

const fs = require('fs');

// Original task data from before HTTP Request replaced the item
const task = $('Read Task').first().json;
const ollamaOut = $input.first().json;
const response = ollamaOut.response || (ollamaOut.error ? 'ERROR: ' + ollamaOut.error : 'ERROR: Empty response');

const vault = task.vault;
const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);

// Confidence detection — mirrors ollama_queue_test.py logic
const lower = response.toLowerCase();
const LOW_WORDS  = ['unsure', 'uncertain', 'not sure', 'unclear'];
const HIGH_WORDS = ['certain', 'confident', 'clear', 'definitive', 'branch is', 'classification is', 'confidence: high'];
const isLow  = LOW_WORDS.some(w => lower.includes(w));
const isHigh = !isLow && HIGH_WORDS.some(w => lower.includes(w));
const confidence = isHigh ? 'HIGH' : 'LOW';

let status, outPath, action, handler;

if (confidence === 'HIGH') {
  const outputContent = [
    '---',
    'TASK_ID: ' + task.task_id,
    'DATE: ' + ts,
    'PROCESSED_BY: OLLAMA',
    'STATUS: DRAFT',
    'REVIEW_REQUIRED: YES',
    '---',
    '',
    '# OUTPUT — ' + task.topic,
    '',
    response,
    ''
  ].join('\n');

  const outputDir = vault + '/99_INBOX/OUTPUTS';
  fs.mkdirSync(outputDir, { recursive: true });
  outPath = task.output_target || (outputDir + '/' + task.task_id + '_RESULT.md');
  fs.writeFileSync(outPath, outputContent, 'utf8');
  status  = 'COMPLETE';
  action  = 'OLLAMA_' + task.task_type + ' (HIGH CONFIDENCE)';
  handler = 'OLLAMA';
} else {
  const handoff = {
    handoff_id:            task.task_id + '-HANDOFF',
    task_type:             'REASONING',
    priority:              task.priority,
    source_task:           task.file_path,
    context_budget_tokens: 1500,
    summary:               response.split(/(?<=[.!?])\s+/).slice(0, 3).join(' '),
    key_findings:          [],
    unresolved:            [response],
    relevant_files:        [],
    do_not_include:        [],
    ollama_confidence:     'LOW',
    escalation_reason:     'ollama_confidence=LOW — escalated to Claude'
  };
  const handoffsDir = vault + '/99_INBOX/HANDOFFS';
  fs.mkdirSync(handoffsDir, { recursive: true });
  outPath = handoffsDir + '/' + task.task_id + '_HANDOFF.json';
  fs.writeFileSync(outPath, JSON.stringify(handoff, null, 2), 'utf8');
  status  = 'ESCALATED';
  action  = 'ESCALATE_TO_CLAUDE (LOW CONFIDENCE)';
  handler = 'CLAUDE';
}

// Update task JSON status in QUEUE/
const taskData = JSON.parse(fs.readFileSync(task.file_path, 'utf8'));
taskData.status = status;
taskData.processed_at = ts;
taskData.output_written_to = outPath;
fs.writeFileSync(task.file_path, JSON.stringify(taskData, null, 2), 'utf8');

// Append table row to DECISION_LOG.md
const row = `| ${ts} | ${task.task_id} | ${action} | ${handler} | ${status} | ${outPath.replace(vault, '%VAULT%')} |\n`;
fs.appendFileSync(vault + '/99_INBOX/DECISION_LOG.md', row, 'utf8');

return [{ json: { task_id: task.task_id, topic: task.topic, status, confidence, output: outPath } }];

const fs = require('fs');

const task = $input.first().json;
const vault = task.vault;
const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);

// RESEARCH tasks → write HANDOFF for Claude (no Perplexity integration)
const handoff = {
  handoff_id:            task.task_id + '-HANDOFF',
  task_type:             'RESEARCH',
  priority:              task.priority,
  source_task:           task.file_path,
  context_budget_tokens: 1500,
  summary:               'task_type=RESEARCH requires deep research — direct handoff to Claude.',
  key_findings:          [],
  unresolved:            [task.prompt],
  relevant_files:        [],
  do_not_include:        [],
  ollama_confidence:     'N/A',
  escalation_reason:     'task_type=RESEARCH — direct handoff, no Perplexity integration active'
};

const handoffsDir = vault + '/99_INBOX/HANDOFFS';
fs.mkdirSync(handoffsDir, { recursive: true });
const outPath = handoffsDir + '/' + task.task_id + '_HANDOFF.json';
fs.writeFileSync(outPath, JSON.stringify(handoff, null, 2), 'utf8');

const taskData = JSON.parse(fs.readFileSync(task.file_path, 'utf8'));
taskData.status = 'ESCALATED';
taskData.processed_at = ts;
taskData.output_written_to = outPath;
fs.writeFileSync(task.file_path, JSON.stringify(taskData, null, 2), 'utf8');

const status = 'ESCALATED';
const action = 'RESEARCH_HANDOFF';
const handler = 'CLAUDE';

const row = `| ${ts} | ${task.task_id} | ${action} | ${handler} | ${status} | ${outPath.replace(vault, '%VAULT%')} |\n`;
fs.appendFileSync(vault + '/99_INBOX/DECISION_LOG.md', row, 'utf8');

return [{ json: { task_id: task.task_id, route: task.route, status, output: outPath } }];
